import React, { useState } from 'react';
import { useBrandStore } from '@/shared/stores/brandStore';
import {
  Select,
  MenuItem,
  FormControl,
  type SelectChangeEvent,
  Box,
  Typography,
} from '@mui/material';
import StoreIcon from '@mui/icons-material/Store';

/**
 * BrandSwitcher — brand dropdown selector in the topbar.
 * Switches the global current brand via brandStore.
 */
const BrandSwitcher: React.FC = () => {
  const brands = useBrandStore((s) => s.brands);
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const switchBrand = useBrandStore((s) => s.switchBrand);

  const handleChange = (event: SelectChangeEvent<string>) => {
    switchBrand(event.target.value);
  };

  return (
    <FormControl size="small" sx={{ minWidth: 180 }}>
      <Select
        value={currentBrandId || ''}
        onChange={handleChange}
        displayEmpty
        sx={{
          color: 'text.primary',
          '.MuiOutlinedInput-notchedOutline': { borderColor: 'divider' },
          '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: 'primary.main' },
          '.MuiSvgIcon-root': { color: 'text.secondary' },
        }}
        renderValue={(selected) => {
          if (!selected) {
            return (
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <StoreIcon fontSize="small" />
                <Typography variant="body2" color="text.secondary">
                  选择品牌
                </Typography>
              </Box>
            );
          }
          const brand = brands.find((b) => b.id === selected);
          return (
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <StoreIcon fontSize="small" color="primary" />
              <Typography variant="body2" fontWeight={600}>
                {brand?.name || '未知品牌'}
              </Typography>
            </Box>
          );
        }}
      >
        {brands.length === 0 && (
          <MenuItem disabled>
            <Typography variant="body2" color="text.secondary">
              暂无品牌，请先创建
            </Typography>
          </MenuItem>
        )}
        {brands.map((brand) => (
          <MenuItem key={brand.id} value={brand.id}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <StoreIcon fontSize="small" />
              <Typography variant="body2">{brand.name}</Typography>
            </Box>
          </MenuItem>
        ))}
      </Select>
    </FormControl>
  );
};

export default BrandSwitcher;
