import { create } from 'zustand';
import { nanoid } from 'nanoid';
import type { Comment, ImportHistory } from '../types/comment';
import {
  getCommentsByBrand,
  getUnanalyzedComments,
  bulkPutComments,
  getImportHistory,
  addImportHistory,
  countCommentsByBrand,
} from '../db/comment.db';
import { db } from '../db/db';
import { computeSourceHash } from '../utils/dedup';

interface CommentFilters {
  platform: string;
  type: string;
  sentiment: string;
  category: string;
  search: string;
}

interface CommentState {
  comments: Comment[];
  totalCount: number;
  page: number;
  pageSize: number;
  filters: CommentFilters;
  importHistory: ImportHistory[];
  isLoading: boolean;

  loadComments: (brandId: string) => Promise<void>;
  loadUnanalyzed: (brandId: string) => Promise<Comment[]>;
  loadImportHistory: (brandId: string) => Promise<void>;
  importComments: (
    brandId: string,
    newComments: Comment[],
    importMeta: Omit<ImportHistory, 'id'>,
  ) => Promise<{ imported: number; duplicated: number; errors: number }>;
  setFilter: (key: keyof CommentFilters, value: string) => void;
  setPage: (page: number) => void;
  setPageSize: (pageSize: number) => void;
  getFilteredComments: () => Comment[];
}

const defaultFilters: CommentFilters = {
  platform: '',
  type: '',
  sentiment: '',
  category: '',
  search: '',
};

/**
 * Apply current filters to comment list and return filtered + paginated result.
 */
function applyFilters(
  comments: Comment[],
  filters: CommentFilters,
): Comment[] {
  let result = [...comments];

  if (filters.platform) {
    result = result.filter((c) => c.platform === filters.platform);
  }
  if (filters.type) {
    result = result.filter((c) => c.type === filters.type);
  }
  if (filters.sentiment) {
    result = result.filter((c) => c.sentiment === filters.sentiment);
  }
  if (filters.category) {
    result = result.filter((c) => c.category === filters.category);
  }
  if (filters.search) {
    const q = filters.search.toLowerCase();
    result = result.filter(
      (c) =>
        c.content.toLowerCase().includes(q) ||
        c.userName.toLowerCase().includes(q) ||
        c.platform.toLowerCase().includes(q),
    );
  }

  return result;
}

export const useCommentStore = create<CommentState>((set, get) => ({
  comments: [],
  totalCount: 0,
  page: 1,
  pageSize: 50,
  filters: { ...defaultFilters },
  importHistory: [],
  isLoading: false,

  loadComments: async (brandId: string) => {
    set({ isLoading: true });
    try {
      const comments = await getCommentsByBrand(brandId);
      set({ comments, totalCount: comments.length, isLoading: false });
    } catch (err) {
      console.error('Failed to load comments:', err);
      set({ isLoading: false });
    }
  },

  loadUnanalyzed: async (brandId: string) => {
    return getUnanalyzedComments(brandId);
  },

  loadImportHistory: async (brandId: string) => {
    try {
      const history = await getImportHistory(brandId);
      // Sort by timestamp descending
      history.sort(
        (a, b) =>
          new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime(),
      );
      set({ importHistory: history });
    } catch (err) {
      console.error('Failed to load import history:', err);
    }
  },

  importComments: async (
    brandId: string,
    newComments: Comment[],
    importMeta: Omit<ImportHistory, 'id'>,
  ): Promise<{ imported: number; duplicated: number; errors: number }> => {
    const existingComments = await getCommentsByBrand(brandId);
    const existingHashes = new Set(
      existingComments.map((c) => c.sourceHash).filter(Boolean),
    );

    // Get max existing ID for continuation
    const maxId = existingComments.reduce(
      (max, c) => Math.max(max, c.id || 0),
      0,
    );

    const batchId = importMeta.fileName
      ? `import_${Date.now()}_${nanoid(8)}`
      : `paste_${Date.now()}_${nanoid(8)}`;

    const toImport: Comment[] = [];
    let duplicatedCount = 0;
    let errorCount = 0;

    for (let i = 0; i < newComments.length; i++) {
      const comment = { ...newComments[i] };

      // Skip empty content
      if (!comment.content || !comment.content.trim()) {
        errorCount++;
        continue;
      }

      const hash = computeSourceHash(comment);
      comment.sourceHash = hash;
      comment.brandId = brandId;
      comment.importBatchId = batchId;
      comment.importedAt = new Date().toISOString();
      comment.isAnalyzed = false;

      if (existingHashes.has(hash)) {
        duplicatedCount++;
      } else {
        // Assign new sequential ID
        comment.id = maxId + toImport.length + 1;
        toImport.push(comment);
        existingHashes.add(hash);
      }
    }

    // Bulk insert non-duplicate comments
    if (toImport.length > 0) {
      await bulkPutComments(toImport);
    }

    // Record import history
    const historyRecord: ImportHistory = {
      id: `ih_${nanoid()}`,
      ...importMeta,
      brandId,
      imported: toImport.length,
      duplicated: duplicatedCount,
      errors: errorCount,
    };
    await addImportHistory(historyRecord);

    // Reload comments and history
    await get().loadComments(brandId);
    await get().loadImportHistory(brandId);

    // Update brand stats
    const totalComments = await countCommentsByBrand(brandId);
    await db.brands.update(brandId, {
      stats: {
        totalComments,
        confirmedInsights: 0,
        strategyCards: { total: 0, active: 0, draft: 0, archived: 0 },
        lastImportAt: new Date().toISOString(),
      },
    });

    return {
      imported: toImport.length,
      duplicated: duplicatedCount,
      errors: errorCount,
    };
  },

  setFilter: (key: keyof CommentFilters, value: string) => {
    set((state) => ({
      filters: { ...state.filters, [key]: value },
      page: 1,
    }));
  },

  setPage: (page: number) => set({ page }),
  setPageSize: (pageSize: number) => set({ pageSize, page: 1 }),

  getFilteredComments: () => {
    const { comments, filters } = get();
    return applyFilters(comments, filters);
  },
}));
