import React, { useState, useCallback } from 'react';
import { AppBar, Toolbar, IconButton, Box, Tooltip } from '@mui/material';
import SearchIcon from '@mui/icons-material/Search';
import SettingsIcon from '@mui/icons-material/Settings';
import LightModeIcon from '@mui/icons-material/LightMode';
import DarkModeIcon from '@mui/icons-material/DarkMode';
import BrandSwitcher from './BrandSwitcher';
import GlobalSearch from '@/features/search/GlobalSearch';
import { useThemeStore } from '@/shared/stores/themeStore';

const TOPBAR_HEIGHT = 56;

const Topbar: React.FC = () => {
  const [searchOpen, setSearchOpen] = useState(false);
  const themeMode = useThemeStore((s) => s.mode);
  const toggleTheme = useThemeStore((s) => s.toggleTheme);

  const handleOpenSearch = useCallback(() => {
    setSearchOpen(true);
  }, []);

  const handleCloseSearch = useCallback(() => {
    setSearchOpen(false);
  }, []);

  return (
    <>
      <AppBar
        position="sticky"
        elevation={0}
        sx={{
          height: TOPBAR_HEIGHT,
          bgcolor: 'background.default',
          borderBottom: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Toolbar sx={{ minHeight: TOPBAR_HEIGHT, px: 3, gap: 2 }}>
          <BrandSwitcher />

          {/* Spacer */}
          <Box sx={{ flexGrow: 1 }} />

          {/* Theme toggle */}
          <Tooltip title={themeMode === 'dark' ? '切换亮色模式' : '切换暗色模式'}>
            <IconButton size="small" color="inherit" onClick={toggleTheme}>
              {themeMode === 'dark' ? <LightModeIcon /> : <DarkModeIcon />}
            </IconButton>
          </Tooltip>

          {/* Global search */}
          <Tooltip title="全局搜索 (Ctrl+K)">
            <IconButton size="small" color="inherit" onClick={handleOpenSearch}>
              <SearchIcon />
            </IconButton>
          </Tooltip>

          {/* Settings */}
          <Tooltip title="系统设置">
            <IconButton size="small" color="inherit">
              <SettingsIcon />
            </IconButton>
          </Tooltip>
        </Toolbar>
      </AppBar>

      {/* Global Search Dialog */}
      <GlobalSearch open={searchOpen} onClose={handleCloseSearch} />
    </>
  );
};

export default Topbar;
