import Dexie, { type Table } from 'dexie';
import type { Brand } from '../types/brand';
import type { Comment, ImportHistory } from '../types/comment';
import type { Insight } from '../types/insight';
import type { StrategyCard, WeeklySnapshot } from '../types/strategy';
import type { Category } from '../types/category';
import type { CallLog } from '../types/common';

/**
 * VOS 2.0 main database instance.
 * Manages 9 tables: brands, comments, importHistory, insights,
 * strategyCards, weeklySnapshots, categories, settings, callLogs.
 */
export class VOSDatabase extends Dexie {
  brands!: Table<Brand, string>;
  comments!: Table<Comment, number>;
  importHistory!: Table<ImportHistory, string>;
  insights!: Table<Insight, string>;
  strategyCards!: Table<StrategyCard, string>;
  weeklySnapshots!: Table<WeeklySnapshot, string>;
  categories!: Table<Category, string>;
  settings!: Table<{ key: string; value: unknown }, string>;
  callLogs!: Table<CallLog, number>;

  constructor() {
    super('vos2');

    this.version(1).stores({
      brands: 'id, name, categoryId',
      comments: 'id, brandId, [brandId+isAnalyzed], [brandId+platform], sourceHash',
      importHistory: 'id, brandId, timestamp',
      insights: 'id, brandId, [brandId+type], [brandId+reviewStatus]',
      strategyCards: 'id, brandId, [brandId+platform], [brandId+reviewStatus]',
      weeklySnapshots: 'id, brandId, weekStart',
      categories: 'id, name',
      settings: 'key',
      callLogs: '++id',
    });
  }
}

/** Singleton database instance */
export const db = new VOSDatabase();
