import React, { useEffect } from 'react';
import { Outlet } from 'react-router-dom';
import { Box } from '@mui/material';
import Sidebar from './Sidebar';
import Topbar from './Topbar';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useCommentStore } from '@/shared/stores/commentStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import { useReviewStore } from '@/shared/stores/reviewStore';

/**
 * Global application layout.
 * Sidebar (permanent) + Topbar (sticky) + Main content area.
 *
 * Brand switch linkage: when currentBrandId changes, trigger
 * reload of all data stores so every page shows fresh data.
 */
const AppLayout: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);

  // ── Brand switching global linkage ──
  useEffect(() => {
    if (!currentBrandId) return;

    // Reload all data stores for the newly selected brand
    Promise.allSettled([
      useCommentStore.getState().loadComments(currentBrandId),
      useInsightStore.getState().loadInsights(currentBrandId),
      useReviewStore.getState().loadAllReviewItems(currentBrandId),
    ]).then((results) => {
      const failed = results.filter((r) => r.status === 'rejected');
      if (failed.length > 0) {
        console.warn(
          `[AppLayout] Brand switch: ${failed.length} store(s) failed to reload for brand=${currentBrandId}`,
          failed,
        );
      }
    });
  }, [currentBrandId]);

  return (
    <Box sx={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      <Sidebar />
      <Box
        component="main"
        sx={{
          flexGrow: 1,
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden',
          bgcolor: 'background.default',
        }}
      >
        <Topbar />
        <Box
          sx={{
            flexGrow: 1,
            overflow: 'auto',
            p: 3,
          }}
        >
          <Outlet />
        </Box>
      </Box>
    </Box>
  );
};

export default AppLayout;
