import React, { useEffect, useState, useCallback } from 'react';
import {
  ThemeProvider,
  CssBaseline,
  Box,
  Typography,
  Button,
  CircularProgress,
  TextField,
  Snackbar,
  Alert,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import StoreIcon from '@mui/icons-material/Store';
import { nanoid } from 'nanoid';
import { defaultTheme, getTheme } from './app/theme/theme';
import { useBrandStore } from './shared/stores/brandStore';
import { useThemeStore } from './shared/stores/themeStore';
import { migrateV1ToV2, hasV1Data, type MigrationResult } from './shared/utils/migrate';
import AppRouter from './app/router/AppRouter';
import type { Brand } from './shared/types/brand';

/** Onboarding page shown when no brands exist */
const OnboardingPage: React.FC<{ onCreateBrand: (brand: Brand) => Promise<void> }> = ({
  onCreateBrand,
}) => {
  const [name, setName] = useState('');
  const [industry, setIndustry] = useState('');
  const [creating, setCreating] = useState(false);
  const [error, setError] = useState('');

  const handleCreate = async () => {
    if (!name.trim()) {
      setError('请输入品牌名称');
      return;
    }
    if (!industry.trim()) {
      setError('请输入所属行业');
      return;
    }

    setCreating(true);
    setError('');

    const newBrand: Brand = {
      id: `brand_${nanoid(8)}`,
      name: name.trim(),
      industry: industry.trim(),
      categoryId: null,
      logoUrl: '',
      createdAt: new Date().toISOString(),
      config: {
        products: [],
        brandStory: '',
        visualStyle: '',
        tone: '',
        keywords: {
          brandWords: [],
          categoryWords: [],
          sceneWords: [],
          audienceWords: [],
        },
        contentGuidelines: {
          do: [],
          dont: [],
        },
      },
      competitors: [],
      stats: {
        totalComments: 0,
        confirmedInsights: 0,
        strategyCards: { total: 0, active: 0, draft: 0, archived: 0 },
        lastImportAt: null,
      },
    };

    try {
      await onCreateBrand(newBrand);
    } catch (err) {
      setError(`创建失败：${err instanceof Error ? err.message : '未知错误'}`);
      setCreating(false);
    }
  };

  return (
    <Box
      sx={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        bgcolor: 'background.default',
        gap: 4,
        px: 2,
      }}
    >
      {/* Logo */}
      <Box sx={{ textAlign: 'center' }}>
        <Box
          sx={{
            width: 64,
            height: 64,
            borderRadius: 3,
            bgcolor: 'primary.main',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#fff',
            fontWeight: 800,
            fontSize: 28,
            mx: 'auto',
            mb: 2,
          }}
        >
          V
        </Box>
        <Typography variant="h4" fontWeight={800} gutterBottom>
          欢迎使用 VOS 2.0
        </Typography>
        <Typography variant="body1" color="text.secondary" sx={{ maxWidth: 480 }}>
          Voice of Consumer — 评论驱动的品牌内容投放决策系统。
          创建第一个品牌以开始使用。
        </Typography>
      </Box>

      {/* Quick create form */}
      <Box
        component="form"
        onSubmit={(e) => {
          e.preventDefault();
          handleCreate();
        }}
        sx={{
          width: '100%',
          maxWidth: 400,
          display: 'flex',
          flexDirection: 'column',
          gap: 2,
          p: 3,
          borderRadius: 3,
          border: '1px solid',
          borderColor: 'divider',
          bgcolor: 'background.paper',
        }}
      >
        <Typography variant="subtitle1" fontWeight={600}>
          快捷创建品牌
        </Typography>
        <TextField
          label="品牌名称"
          value={name}
          onChange={(e) => {
            setName(e.target.value);
            setError('');
          }}
          required
          fullWidth
          autoFocus
          placeholder="例如：轻氧护肤"
          disabled={creating}
        />
        <TextField
          label="所属行业"
          value={industry}
          onChange={(e) => {
            setIndustry(e.target.value);
            setError('');
          }}
          required
          fullWidth
          placeholder="例如：新消费护肤"
          disabled={creating}
        />
        {error && (
          <Typography variant="body2" color="error">
            {error}
          </Typography>
        )}
        <Button
          type="submit"
          variant="contained"
          size="large"
          startIcon={creating ? <CircularProgress size={18} color="inherit" /> : <AddIcon />}
          disabled={creating}
          fullWidth
        >
          {creating ? '创建中...' : '创建第一个品牌'}
        </Button>
      </Box>

      <Typography variant="body2" color="text.secondary">
        品牌创建后可在「品牌管理」中编辑完整配置
      </Typography>
    </Box>
  );
};

/**
 * App root component.
 * - Detects and runs V1→V2 data migration on first launch with toast notification
 * - Loads brand list from DexieDB
 * - Shows onboarding when no brands exist
 * - Wraps app in MUI ThemeProvider with theme from zustand store
 */
const App: React.FC = () => {
  const [initializing, setInitializing] = useState(true);
  const [migrationToast, setMigrationToast] = useState<{
    open: boolean;
    message: string;
    severity: 'success' | 'info' | 'warning';
  }>({ open: false, message: '', severity: 'info' });

  const themeMode = useThemeStore((s) => s.mode);
  const brands = useBrandStore((s) => s.brands);
  const loadBrands = useBrandStore((s) => s.loadBrands);
  const addBrand = useBrandStore((s) => s.addBrand);

  const showMigrationToast = useCallback(
    (result: MigrationResult) => {
      if (result.migrated) {
        setMigrationToast({
          open: true,
          message: `V1 数据迁移完成：${result.brands} 个品牌、${result.comments} 条评论`,
          severity: 'success',
        });
      }
    },
    [],
  );

  useEffect(() => {
    const init = async () => {
      try {
        // Check for V1 data migration
        if (hasV1Data()) {
          console.log('[App] V1 data detected, running migration...');
          const result = await migrateV1ToV2();
          if (result.migrated) {
            console.log(
              `[App] Migration complete: ${result.brands} brands, ${result.comments} comments`,
            );
            showMigrationToast(result);
          }
        }

        // Load brands from DB
        await loadBrands();
      } catch (err) {
        console.error('[App] Initialization error:', err);
      } finally {
        setInitializing(false);
      }
    };

    init();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleCreateBrand = async (brand: Brand) => {
    await addBrand(brand);
  };

  const handleCloseToast = () => {
    setMigrationToast((prev) => ({ ...prev, open: false }));
  };

  const theme = getTheme(themeMode);

  if (initializing) {
    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            height: '100vh',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 2,
            bgcolor: 'background.default',
          }}
        >
          <Box
            sx={{
              width: 48,
              height: 48,
              borderRadius: 2,
              bgcolor: 'primary.main',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#fff',
              fontWeight: 700,
              fontSize: 22,
            }}
          >
            V
          </Box>
          <CircularProgress size={24} />
          <Typography variant="body2" color="text.secondary">
            正在初始化 VOS 2.0...
          </Typography>
        </Box>
      </ThemeProvider>
    );
  }

  // Onboarding: show if no brands
  if (brands.length === 0) {
    return (
      <ThemeProvider theme={theme}>
        <CssBaseline />
        <OnboardingPage onCreateBrand={handleCreateBrand} />
        {/* Migration toast even on onboarding */}
        <Snackbar
          open={migrationToast.open}
          autoHideDuration={5000}
          onClose={handleCloseToast}
          anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
        >
          <Alert
            onClose={handleCloseToast}
            severity={migrationToast.severity}
            variant="filled"
          >
            {migrationToast.message}
          </Alert>
        </Snackbar>
      </ThemeProvider>
    );
  }

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AppRouter />
      {/* Migration result toast */}
      <Snackbar
        open={migrationToast.open}
        autoHideDuration={5000}
        onClose={handleCloseToast}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert
          onClose={handleCloseToast}
          severity={migrationToast.severity}
          variant="filled"
        >
          {migrationToast.message}
        </Alert>
      </Snackbar>
    </ThemeProvider>
  );
};

export default App;
