import { create } from 'zustand';

type ThemeMode = 'light' | 'dark';

interface ThemeState {
  mode: ThemeMode;
  toggleTheme: () => void;
  setTheme: (mode: ThemeMode) => void;
}

/** Read saved theme from localStorage, default dark */
function getInitialTheme(): ThemeMode {
  const stored = localStorage.getItem('vos2-theme');
  return stored === 'light' ? 'light' : 'dark';
}

/** Global theme store — used by App for ThemeProvider and Topbar for toggle */
export const useThemeStore = create<ThemeState>((set) => ({
  mode: getInitialTheme(),

  toggleTheme: () =>
    set((state) => {
      const next: ThemeMode = state.mode === 'light' ? 'dark' : 'light';
      localStorage.setItem('vos2-theme', next);
      return { mode: next };
    }),

  setTheme: (mode: ThemeMode) => {
    localStorage.setItem('vos2-theme', mode);
    set({ mode });
  },
}));
