import React from 'react';
import {
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Divider,
  Typography,
  Box,
  Tooltip,
} from '@mui/material';
import { useNavigate, useLocation } from 'react-router-dom';
import DashboardIcon from '@mui/icons-material/Dashboard';
import RateReviewIcon from '@mui/icons-material/RateReview';
import ChatBubbleIcon from '@mui/icons-material/ChatBubble';
import MapIcon from '@mui/icons-material/Map';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import LightbulbIcon from '@mui/icons-material/Lightbulb';
import MusicNoteIcon from '@mui/icons-material/MusicNote';
import ScienceIcon from '@mui/icons-material/Science';
import AssessmentIcon from '@mui/icons-material/Assessment';
import DescriptionIcon from '@mui/icons-material/Description';
import StoreIcon from '@mui/icons-material/Store';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import CategoryIcon from '@mui/icons-material/Category';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import SettingsIcon from '@mui/icons-material/Settings';

const SIDEBAR_WIDTH = 240;

interface NavGroup {
  label: string;
  items: NavItem[];
}

interface NavItem {
  path: string;
  label: string;
  icon: React.ReactNode;
}

const NAV_GROUPS: NavGroup[] = [
  {
    label: '决策中心',
    items: [
      { path: '/dashboard', label: '决策台', icon: <DashboardIcon /> },
      { path: '/review', label: '审核工作台', icon: <RateReviewIcon /> },
    ],
  },
  {
    label: '数据洞察',
    items: [
      { path: '/comments', label: '评论池', icon: <ChatBubbleIcon /> },
      { path: '/demand-map', label: '需求地图', icon: <MapIcon /> },
      { path: '/barrier-map', label: '障碍地图', icon: <WarningAmberIcon /> },
      { path: '/competitor', label: '竞品机会', icon: <TrendingUpIcon /> },
      { path: '/content-pool', label: '内容池', icon: <ContentCopyIcon /> },
    ],
  },
  {
    label: '内容策略',
    items: [
      { path: '/strategy/xhs', label: '小红书策略', icon: <LightbulbIcon /> },
      { path: '/strategy/dy', label: '抖音策略', icon: <MusicNoteIcon /> },
    ],
  },
  {
    label: '执行工具',
    items: [
      { path: '/content-lab', label: '内容实验室', icon: <ScienceIcon /> },
      { path: '/report', label: '报告中心', icon: <AssessmentIcon /> },
      { path: '/brief-export', label: '导出Brief', icon: <DescriptionIcon /> },
    ],
  },
  {
    label: '知识资产',
    items: [
      { path: '/brands', label: '品牌管理', icon: <StoreIcon /> },
      { path: '/brand-knowledge', label: '品牌知识库', icon: <BookmarkIcon /> },
      { path: '/category', label: '品类知识库', icon: <CategoryIcon /> },
    ],
  },
  {
    label: 'AI 引擎',
    items: [
      { path: '/ai-workbench', label: 'AI 工作台', icon: <SmartToyIcon /> },
    ],
  },
];

const Sidebar: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: SIDEBAR_WIDTH,
        flexShrink: 0,
        '& .MuiDrawer-paper': {
          width: SIDEBAR_WIDTH,
          boxSizing: 'border-box',
          bgcolor: 'background.default',
          borderRight: '1px solid',
          borderColor: 'divider',
          overflowY: 'auto',
        },
      }}
    >
      {/* Logo */}
      <Box
        sx={{
          p: 2,
          display: 'flex',
          alignItems: 'center',
          gap: 1,
          borderBottom: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Box
          sx={{
            width: 32,
            height: 32,
            borderRadius: 1.5,
            bgcolor: 'primary.main',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#fff',
            fontWeight: 700,
            fontSize: 16,
          }}
        >
          V
        </Box>
        <Typography variant="h6" fontWeight={700} fontSize={18}>
          VOS 2.0
        </Typography>
      </Box>

      {/* Navigation */}
      <Box sx={{ flex: 1, overflowY: 'auto', py: 1 }}>
        {NAV_GROUPS.map((group, gIdx) => (
          <Box key={group.label}>
            <Typography
              variant="caption"
              sx={{
                px: 2.5,
                py: 1,
                display: 'block',
                color: 'text.secondary',
                fontWeight: 600,
                textTransform: 'uppercase',
                fontSize: 11,
                letterSpacing: 0.5,
              }}
            >
              {group.label}
            </Typography>
            <List dense disablePadding>
              {group.items.map((item) => {
                const isActive = location.pathname === item.path ||
                  (item.path !== '/' && location.pathname.startsWith(item.path + '/'));
                return (
                  <ListItem key={item.path} disablePadding>
                    <ListItemButton
                      onClick={() => navigate(item.path)}
                      sx={{
                        mx: 1,
                        borderRadius: 1.5,
                        mb: 0.25,
                        minHeight: 36,
                        bgcolor: isActive ? 'action.selected' : 'transparent',
                        color: isActive ? 'primary.main' : 'text.secondary',
                        '&:hover': {
                          bgcolor: 'action.hover',
                        },
                      }}
                    >
                      <ListItemIcon
                        sx={{
                          minWidth: 36,
                          color: isActive ? 'primary.main' : 'text.secondary',
                        }}
                      >
                        {item.icon}
                      </ListItemIcon>
                      <ListItemText
                        primary={item.label}
                        primaryTypographyProps={{
                          fontSize: 13,
                          fontWeight: isActive ? 600 : 400,
                        }}
                      />
                    </ListItemButton>
                  </ListItem>
                );
              })}
            </List>
            {gIdx < NAV_GROUPS.length - 1 && (
              <Divider sx={{ my: 1, mx: 2 }} />
            )}
          </Box>
        ))}
      </Box>

      {/* Bottom: Settings */}
      <Box sx={{ borderTop: '1px solid', borderColor: 'divider', p: 1 }}>
        <ListItemButton
          onClick={() => navigate('/settings')}
          sx={{ borderRadius: 1.5, minHeight: 36 }}
        >
          <ListItemIcon sx={{ minWidth: 36 }}>
            <SettingsIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText
            primary="系统设置"
            primaryTypographyProps={{ fontSize: 13 }}
          />
        </ListItemButton>
      </Box>
    </Drawer>
  );
};

export default Sidebar;
