import { db } from './db';
import type { StrategyCard } from '../types/strategy';

/** Get strategy cards for a brand */
export async function getStrategyCardsByBrand(brandId: string): Promise<StrategyCard[]> {
  return db.strategyCards.where({ brandId }).toArray();
}

/** Get strategy cards by brand and platform */
export async function getStrategyCardsByPlatform(
  brandId: string,
  platform: 'xhs' | 'dy',
): Promise<StrategyCard[]> {
  return db.strategyCards.where({ brandId, platform }).toArray();
}

/** Get strategy cards by review status */
export async function getStrategyCardsByReviewStatus(
  brandId: string,
  reviewStatus: 'pending' | 'confirmed' | 'rejected',
): Promise<StrategyCard[]> {
  return db.strategyCards.where({ brandId, reviewStatus }).toArray();
}

/** Put a strategy card (insert or update) */
export async function putStrategyCard(card: StrategyCard): Promise<void> {
  await db.strategyCards.put(card);
}

/** Bulk put strategy cards */
export async function bulkPutStrategyCards(cards: StrategyCard[]): Promise<void> {
  await db.strategyCards.bulkPut(cards);
}

/** Get a single strategy card */
export async function getStrategyCard(id: string): Promise<StrategyCard | undefined> {
  return db.strategyCards.get(id);
}

/** Update strategy card review status */
export async function updateStrategyCardReview(
  id: string,
  reviewStatus: 'confirmed' | 'rejected',
  reviewLog: StrategyCard['reviewLog'],
): Promise<void> {
  await db.strategyCards.update(id, { reviewStatus, reviewLog });
}

/** Count strategy cards by brand */
export async function countStrategyCards(brandId: string): Promise<number> {
  return db.strategyCards.where({ brandId }).count();
}
