import { db } from './db';
import type { Insight } from '../types/insight';

/** Get all insights for a brand */
export async function getInsightsByBrand(brandId: string): Promise<Insight[]> {
  return db.insights.where({ brandId }).toArray();
}

/** Get pending insights for a brand */
export async function getPendingInsights(brandId: string): Promise<Insight[]> {
  return db.insights.where({ brandId, reviewStatus: 'pending' }).toArray();
}

/** Get confirmed insights for a brand */
export async function getConfirmedInsights(brandId: string): Promise<Insight[]> {
  return db.insights.where({ brandId, reviewStatus: 'confirmed' }).toArray();
}

/** Bulk put insights */
export async function bulkPutInsights(insights: Insight[]): Promise<void> {
  await db.insights.bulkPut(insights);
}

/** Update insight review status */
export async function updateInsightReview(
  id: string,
  reviewStatus: 'confirmed' | 'rejected',
  reviewLog: Insight['reviewLog'],
  editedContent?: string,
): Promise<void> {
  const updates: Partial<Insight> = { reviewStatus, reviewLog };
  if (editedContent) updates.editedContent = editedContent;
  await db.insights.update(id, updates);
}

/** Get a single insight */
export async function getInsight(id: string): Promise<Insight | undefined> {
  return db.insights.get(id);
}

/** Count pending insights for a brand */
export async function countPendingInsights(brandId: string): Promise<number> {
  return db.insights.where({ brandId, reviewStatus: 'pending' }).count();
}
