import React, { Suspense, lazy } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { Box, CircularProgress, Typography } from '@mui/material';
import AppLayout from '@/app/layout/AppLayout';

/** Loading fallback */
const PageLoading: React.FC = () => (
  <Box
    sx={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      height: '100%',
      gap: 2,
    }}
  >
    <CircularProgress size={32} />
    <Typography variant="body2" color="text.secondary">
      加载中...
    </Typography>
  </Box>
);

/** Lazy-loaded page components */
const DashboardPage = lazy(() => import('@/features/dashboard/DashboardPage'));
const ReviewWorkbenchPage = lazy(() => import('@/features/insights/ReviewWorkbenchPage'));
const CommentPoolPage = lazy(() => import('@/features/comments/CommentPoolPage'));
const DemandMapPage = lazy(() => import('@/features/insights/DemandMapPage'));
const BarrierMapPage = lazy(() => import('@/features/insights/BarrierMapPage'));
const CompetitorPage = lazy(() => import('@/features/insights/CompetitorPage'));
const ContentPoolPage = lazy(() => import('@/features/content/ContentPoolPage'));
const StrategyPage = lazy(() => import('@/features/strategy/StrategyPage'));
const ContentLabPage = lazy(() => import('@/features/content/ContentLabPage'));
const ReportCenterPage = lazy(() => import('@/features/report/ReportCenterPage'));
const BriefExportPage = lazy(() => import('@/features/strategy/BriefExportPage'));
const BrandListPage = lazy(() => import('@/features/brand/BrandListPage'));
const BrandKnowledgePage = lazy(() => import('@/features/brand/BrandKnowledgePage'));
const CategoryKnowledgePage = lazy(() => import('@/features/category/CategoryKnowledgePage'));
const StrategyDetailPage = lazy(() => import('@/features/strategy/StrategyDetailPage'));
const AIWorkbenchPage = lazy(() => import('@/features/ai/AIWorkbenchPage'));

/** AppRouter — defines all application routes */
const AppRouter: React.FC = () => {
  return (
    <Suspense fallback={<PageLoading />}>
      <Routes>
        <Route element={<AppLayout />}>
          {/* 决策中心 */}
          <Route path="/dashboard" element={<DashboardPage />} />
          <Route path="/review" element={<ReviewWorkbenchPage />} />

          {/* 数据洞察 */}
          <Route path="/comments" element={<CommentPoolPage />} />
          <Route path="/demand-map" element={<DemandMapPage />} />
          <Route path="/barrier-map" element={<BarrierMapPage />} />
          <Route path="/competitor" element={<CompetitorPage />} />
          <Route path="/content-pool" element={<ContentPoolPage />} />

          {/* 内容策略 */}
          <Route path="/strategy/xhs" element={<StrategyPage />} />
          <Route path="/strategy/dy" element={<StrategyPage />} />
          <Route path="/strategy/:platform/detail/:id" element={<StrategyDetailPage />} />

          {/* 执行工具 */}
          <Route path="/content-lab" element={<ContentLabPage />} />
          <Route path="/report" element={<ReportCenterPage />} />
          <Route path="/brief-export" element={<BriefExportPage />} />

          {/* 知识资产 */}
          <Route path="/brands" element={<BrandListPage />} />
          <Route path="/brand-knowledge" element={<BrandKnowledgePage />} />
          <Route path="/category" element={<CategoryKnowledgePage />} />

          {/* AI 引擎 */}
          <Route path="/ai-workbench" element={<AIWorkbenchPage />} />

          {/* Default redirect */}
          <Route path="/" element={<Navigate to="/dashboard" replace />} />
          <Route path="*" element={<Navigate to="/dashboard" replace />} />
        </Route>
      </Routes>
    </Suspense>
  );
};

export default AppRouter;
