import { create } from 'zustand';
import type { Insight, ReviewLog } from '../types/insight';
import {
  getInsightsByBrand,
  updateInsightReview,
  countPendingInsights,
  bulkPutInsights,
} from '../db/insight.db';

interface InsightState {
  insights: Insight[];
  pendingCount: number;
  reviewFilter: 'pending' | 'confirmed' | 'rejected' | 'all';
  isLoading: boolean;

  loadInsights: (brandId: string) => Promise<void>;
  setReviewFilter: (filter: 'pending' | 'confirmed' | 'rejected' | 'all') => void;
  addInsight: (insight: Insight) => Promise<void>;
  confirmInsight: (id: string, operator?: string) => Promise<void>;
  rejectInsight: (id: string, reason: string, operator?: string) => Promise<void>;
  editInsight: (id: string, newContent: string, operator?: string) => Promise<void>;
  batchConfirm: (ids: string[]) => Promise<void>;
  getPendingCount: (brandId: string) => Promise<number>;
}

/** Create a review log entry */
function createLogEntry(
  action: ReviewLog['action'],
  operator: string,
  changes?: string,
): ReviewLog {
  return {
    action,
    timestamp: new Date().toISOString(),
    operator,
    changes: changes ?? null,
  };
}

export const useInsightStore = create<InsightState>((set, get) => ({
  insights: [],
  pendingCount: 0,
  reviewFilter: 'all',
  isLoading: false,

  loadInsights: async (brandId: string) => {
    set({ isLoading: true });
    try {
      const insights = await getInsightsByBrand(brandId);
      const pendingCount = await countPendingInsights(brandId);
      set({ insights, pendingCount, isLoading: false });
    } catch (err) {
      console.error('Failed to load insights:', err);
      set({ isLoading: false });
    }
  },

  setReviewFilter: (reviewFilter) => set({ reviewFilter }),

  addInsight: async (insight: Insight) => {
    await bulkPutInsights([insight]);
    set((state) => ({
      insights: [...state.insights, insight],
      pendingCount: state.pendingCount + (insight.reviewStatus === 'pending' ? 1 : 0),
    }));
  },

  confirmInsight: async (id: string, operator: string = '老薛') => {
    const logEntry = createLogEntry('confirmed', operator);
    const insight = get().insights.find((i) => i.id === id);
    if (!insight) return;
    const reviewLog = [...insight.reviewLog, logEntry];
    await updateInsightReview(id, 'confirmed', reviewLog);
    set((state) => ({
      insights: state.insights.map((i) =>
        i.id === id ? { ...i, reviewStatus: 'confirmed' as const, reviewLog } : i,
      ),
      pendingCount: state.pendingCount - (insight.reviewStatus === 'pending' ? 1 : 0),
    }));
  },

  rejectInsight: async (id: string, reason: string, operator: string = '老薛') => {
    const logEntry = createLogEntry('rejected', operator, reason);
    const insight = get().insights.find((i) => i.id === id);
    if (!insight) return;
    const reviewLog = [...insight.reviewLog, logEntry];
    await updateInsightReview(id, 'rejected', reviewLog);
    set((state) => ({
      insights: state.insights.map((i) =>
        i.id === id ? { ...i, reviewStatus: 'rejected' as const, reviewLog } : i,
      ),
      pendingCount: state.pendingCount - (insight.reviewStatus === 'pending' ? 1 : 0),
    }));
  },

  editInsight: async (id: string, newContent: string, operator: string = '老薛') => {
    const insight = get().insights.find((i) => i.id === id);
    if (!insight) return;
    const logEntry = createLogEntry('edited', operator, '人工编辑内容');
    const reviewLog = [...insight.reviewLog, logEntry];
    await updateInsightReview(id, 'confirmed', reviewLog, newContent);
    set((state) => ({
      insights: state.insights.map((i) =>
        i.id === id
          ? {
              ...i,
              originalContent: i.originalContent ?? i.content,
              editedContent: newContent,
              content: newContent,
              reviewStatus: 'confirmed' as const,
              reviewLog,
            }
          : i,
      ),
      pendingCount: state.pendingCount - (insight.reviewStatus === 'pending' ? 1 : 0),
    }));
  },

  batchConfirm: async (ids: string[]) => {
    for (const id of ids) {
      await get().confirmInsight(id);
    }
  },

  getPendingCount: async (brandId: string) => {
    const count = await countPendingInsights(brandId);
    set({ pendingCount: count });
    return count;
  },
}));
