import CryptoJS from 'crypto-js';
import type { Comment } from '../types/comment';

/**
 * Compute a source hash for comment deduplication.
 * Uses MD5(videoId|userUid|first50chars of content)
 */
export function computeSourceHash(comment: Partial<Comment>): string {
  const contentPrefix = (comment.content || '').substring(0, 50);
  const raw = `${comment.videoId || ''}|${comment.userUid || ''}|${contentPrefix}`;
  return CryptoJS.MD5(raw).toString();
}

/**
 * Find duplicates between new and existing comments based on sourceHash.
 * Returns the IDs of existing comments that are duplicates.
 */
export function findDuplicates(
  newComments: Partial<Comment>[],
  existingSourceHashes: Set<string>,
): { duplicates: Partial<Comment>[]; unique: Partial<Comment>[] } {
  const duplicates: Partial<Comment>[] = [];
  const unique: Partial<Comment>[] = [];

  for (const comment of newComments) {
    const hash = computeSourceHash(comment);
    if (existingSourceHashes.has(hash)) {
      duplicates.push(comment);
    } else {
      unique.push({ ...comment, sourceHash: hash });
      existingSourceHashes.add(hash);
    }
  }

  return { duplicates, unique };
}
