/**
 * GlobalSearch — Cross-module search with debounce and grouped results.
 *
 * Features:
 * - Integrated in Topbar (search icon opens dialog)
 * - Search scope: comments(content), strategy cards(title), brands(industry), insights(title)
 * - 300ms debounce
 * - Results grouped by module
 * - Click result → navigate to corresponding page
 */
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  TextField,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Typography,
  IconButton,
  Box,
  Divider,
  Chip,
  CircularProgress,
  InputAdornment,
} from '@mui/material';
import SearchIcon from '@mui/icons-material/Search';
import CloseIcon from '@mui/icons-material/Close';
import ChatIcon from '@mui/icons-material/Chat';
import LightbulbIcon from '@mui/icons-material/Lightbulb';
import StoreIcon from '@mui/icons-material/Store';
import CategoryIcon from '@mui/icons-material/Category';
import { useNavigate } from 'react-router-dom';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useDebounce } from '@/shared/hooks/useDebounce';
import type { Comment } from '@/shared/types/comment';
import type { StrategyCard } from '@/shared/types/strategy';
import type { Insight } from '@/shared/types/insight';

interface SearchResult {
  id: string;
  type: 'comment' | 'strategy' | 'insight' | 'brand';
  title: string;
  preview: string;
  navigateTo: string;
}

interface GlobalSearchProps {
  open: boolean;
  onClose: () => void;
}

const GlobalSearch: React.FC<GlobalSearchProps> = ({ open, onClose }) => {
  const navigate = useNavigate();
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const brands = useBrandStore((s) => s.brands);

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [searching, setSearching] = useState(false);
  const debouncedQuery = useDebounce(query, 300);

  useEffect(() => {
    if (!open) {
      setQuery('');
      setResults([]);
    }
  }, [open]);

  useEffect(() => {
    if (!debouncedQuery.trim() || debouncedQuery.length < 2) {
      setResults([]);
      return;
    }

    const q = debouncedQuery.toLowerCase();
    setSearching(true);

    (async () => {
      const all: SearchResult[] = [];

      try {
        // Search comments
        if (currentBrandId) {
          const comments: Comment[] = await db.comments
            .where({ brandId: currentBrandId })
            .filter((c) => c.content.toLowerCase().includes(q))
            .limit(5)
            .toArray();

          comments.forEach((c) => {
            all.push({
              id: `comment-${c.id}`,
              type: 'comment',
              title: c.author || c.userName || '匿名用户',
              preview: c.content.substring(0, 100),
              navigateTo: '/comments',
            });
          });
        }

        // Search strategy cards
        if (currentBrandId) {
          const strategies: StrategyCard[] = await db.strategyCards
            .where({ brandId: currentBrandId })
            .filter(
              (s) =>
                s.title.toLowerCase().includes(q) ||
                (s.subtitle ?? '').toLowerCase().includes(q),
            )
            .limit(5)
            .toArray();

          strategies.forEach((s) => {
            all.push({
              id: `strategy-${s.id}`,
              type: 'strategy',
              title: s.title,
              preview: s.contentDirection?.substring(0, 100) ?? '',
              navigateTo: `/strategy/${s.platform}/detail/${s.id}`,
            });
          });
        }

        // Search insights
        if (currentBrandId) {
          const insights: Insight[] = await db.insights
            .where({ brandId: currentBrandId })
            .filter((i) => i.title.toLowerCase().includes(q))
            .limit(5)
            .toArray();

          insights.forEach((i) => {
            all.push({
              id: `insight-${i.id}`,
              type: 'insight',
              title: i.title,
              preview: i.content.substring(0, 100),
              navigateTo: '/review',
            });
          });
        }

        // Search brands
        brands
          .filter((b) => b.industry.toLowerCase().includes(q) || b.name.toLowerCase().includes(q))
          .slice(0, 3)
          .forEach((b) => {
            all.push({
              id: `brand-${b.id}`,
              type: 'brand',
              title: b.name,
              preview: b.industry,
              navigateTo: '/brands',
            });
          });
      } catch (err) {
        console.error('Search error:', err);
      }

      setResults(all);
      setSearching(false);
    })();
  }, [debouncedQuery, currentBrandId, brands]);

  const handleSelect = useCallback(
    (result: SearchResult) => {
      navigate(result.navigateTo);
      onClose();
    },
    [navigate, onClose],
  );

  const getIcon = (type: string) => {
    switch (type) {
      case 'comment':
        return <ChatIcon fontSize="small" color="action" />;
      case 'strategy':
        return <LightbulbIcon fontSize="small" color="warning" />;
      case 'insight':
        return <LightbulbIcon fontSize="small" color="primary" />;
      case 'brand':
        return <StoreIcon fontSize="small" color="success" />;
      default:
        return <CategoryIcon fontSize="small" />;
    }
  };

  const getTypeLabel = (type: string) => {
    switch (type) {
      case 'comment':
        return '评论';
      case 'strategy':
        return '策略卡';
      case 'insight':
        return '洞察';
      case 'brand':
        return '品牌';
      default:
        return type;
    }
  };

  // Group results by type
  const grouped = useMemo(() => {
    const groups: Record<string, SearchResult[]> = {};
    results.forEach((r) => {
      if (!groups[r.type]) groups[r.type] = [];
      groups[r.type].push(r);
    });
    return groups;
  }, [results]);

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="sm"
      fullWidth
      PaperProps={{
        sx: {
          position: 'fixed',
          top: '10%',
          m: 0,
          maxHeight: '70vh',
        },
      }}
    >
      <DialogTitle sx={{ pb: 1 }}>
        <TextField
          autoFocus
          fullWidth
          variant="outlined"
          size="small"
          placeholder="搜索评论、策略卡、洞察、品牌..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <SearchIcon color="action" />
              </InputAdornment>
            ),
            endAdornment: query ? (
              <InputAdornment position="end">
                <IconButton size="small" onClick={() => setQuery('')}>
                  <CloseIcon fontSize="small" />
                </IconButton>
              </InputAdornment>
            ) : searching ? (
              <InputAdornment position="end">
                <CircularProgress size={16} />
              </InputAdornment>
            ) : null,
          }}
        />
      </DialogTitle>

      <DialogContent sx={{ pt: 1 }}>
        {debouncedQuery.length < 2 ? (
          <Box sx={{ textAlign: 'center', py: 4 }}>
            <SearchIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
            <Typography variant="body2" color="text.secondary">
              输入至少 2 个字符开始搜索
            </Typography>
          </Box>
        ) : searching ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
            <CircularProgress size={24} />
          </Box>
        ) : results.length === 0 ? (
          <Box sx={{ textAlign: 'center', py: 4 }}>
            <Typography variant="body2" color="text.secondary">
              未找到 "{debouncedQuery}" 的相关结果
            </Typography>
          </Box>
        ) : (
          <>
            {/* Results count */}
            <Typography variant="caption" color="text.secondary" sx={{ mb: 1, display: 'block' }}>
              共 {results.length} 条结果
            </Typography>

            {/* Grouped results */}
            {Object.entries(grouped).map(([type, items]) => (
              <Box key={type} sx={{ mb: 2 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5, pl: 1 }}>
                  {getIcon(type)}
                  <Typography variant="caption" fontWeight={600} color="text.secondary">
                    {getTypeLabel(type)}
                  </Typography>
                  <Chip label={items.length} size="small" sx={{ height: 18, fontSize: 10 }} />
                </Box>
                <List dense disablePadding>
                  {items.map((item) => (
                    <ListItem key={item.id} disablePadding>
                      <ListItemButton onClick={() => handleSelect(item)} sx={{ borderRadius: 1 }}>
                        <ListItemText
                          primary={item.title}
                          secondary={item.preview}
                          primaryTypographyProps={{
                            variant: 'body2',
                            fontWeight: 500,
                            noWrap: true,
                          }}
                          secondaryTypographyProps={{
                            variant: 'caption',
                            noWrap: true,
                          }}
                        />
                      </ListItemButton>
                    </ListItem>
                  ))}
                </List>
                <Divider sx={{ mt: 1 }} />
              </Box>
            ))}
          </>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default GlobalSearch;
