import { db } from './db';
import type { Comment, ImportHistory } from '../types/comment';

/** Get comments for a brand with optional filters */
export async function getCommentsByBrand(brandId: string): Promise<Comment[]> {
  return db.comments.where({ brandId }).toArray();
}

/** Get unanalyzed comments for a brand */
export async function getUnanalyzedComments(brandId: string): Promise<Comment[]> {
  return db.comments.where({ brandId, isAnalyzed: false }).toArray();
}

/** Get analyzed comments for a brand */
export async function getAnalyzedComments(brandId: string): Promise<Comment[]> {
  return db.comments.where({ brandId, isAnalyzed: true }).toArray();
}

/** Mark comments as analyzed */
export async function markCommentsAnalyzed(ids: number[]): Promise<void> {
  await db.comments.bulkUpdate(ids.map((id) => ({
    key: id,
    changes: { isAnalyzed: true },
  })));
}

/** Bulk upsert comments */
export async function bulkPutComments(comments: Comment[]): Promise<void> {
  await db.comments.bulkPut(comments);
}

/** Get comment by ID */
export async function getComment(id: number): Promise<Comment | undefined> {
  return db.comments.get(id);
}

/** Count comments by brand */
export async function countCommentsByBrand(brandId: string): Promise<number> {
  return db.comments.where({ brandId }).count();
}

/** Get import history for a brand */
export async function getImportHistory(brandId: string): Promise<ImportHistory[]> {
  return db.importHistory.where({ brandId }).toArray();
}

/** Add an import history record */
export async function addImportHistory(record: ImportHistory): Promise<void> {
  await db.importHistory.put(record);
}
