import { db } from './db';
import type { Brand } from '../types/brand';

/** Get all brands */
export async function getAllBrands(): Promise<Brand[]> {
  return db.brands.toArray();
}

/** Get a single brand by ID */
export async function getBrand(id: string): Promise<Brand | undefined> {
  return db.brands.get(id);
}

/** Create or update a brand */
export async function putBrand(brand: Brand): Promise<string> {
  await db.brands.put(brand);
  return brand.id;
}

/** Update specific brand fields */
export async function updateBrand(id: string, updates: Partial<Brand>): Promise<void> {
  await db.brands.update(id, updates);
}

/** Delete a brand by ID */
export async function deleteBrand(id: string): Promise<void> {
  await db.brands.delete(id);
}

/** Get brand count */
export async function getBrandCount(): Promise<number> {
  return db.brands.count();
}
