import { create } from 'zustand';
import type { Insight } from '../types/insight';
import type { StrategyCard } from '../types/strategy';
import {
  getInsightsByBrand,
  updateInsightReview,
} from '../db/insight.db';
import {
  getStrategyCardsByBrand,
  updateStrategyCardReview,
} from '../db/strategy.db';

/** Unified review item */
export type ReviewItem =
  | (Insight & { itemType: 'insight' })
  | (StrategyCard & { itemType: 'strategy' });

interface ReviewState {
  reviewItems: ReviewItem[];
  activeFilter: 'pending' | 'confirmed' | 'rejected' | 'all';
  selectedIds: string[];

  loadAllReviewItems: (brandId: string) => Promise<void>;
  setActiveFilter: (filter: 'pending' | 'confirmed' | 'rejected' | 'all') => void;
  toggleSelection: (id: string) => void;
  selectAll: () => void;
  clearSelection: () => void;
  confirmItem: (type: 'insight' | 'strategy', id: string) => Promise<void>;
  rejectItem: (type: 'insight' | 'strategy', id: string, reason: string) => Promise<void>;
  batchConfirm: () => Promise<void>;
  batchReject: (reason: string) => Promise<void>;
  getPendingItems: () => ReviewItem[];
}

export const useReviewStore = create<ReviewState>((set, get) => ({
  reviewItems: [],
  activeFilter: 'pending',
  selectedIds: [],

  loadAllReviewItems: async (brandId: string) => {
    const insights = await getInsightsByBrand(brandId);
    const strategyCards = await getStrategyCardsByBrand(brandId);

    const items: ReviewItem[] = [
      ...insights.map((i) => ({ ...i, itemType: 'insight' as const })),
      ...strategyCards.map((s) => ({ ...s, itemType: 'strategy' as const })),
    ];

    set({ reviewItems: items, selectedIds: [] });
  },

  setActiveFilter: (filter) => set({ activeFilter: filter, selectedIds: [] }),

  toggleSelection: (id: string) => {
    set((state) => {
      const selectedIds = state.selectedIds.includes(id)
        ? state.selectedIds.filter((sid) => sid !== id)
        : [...state.selectedIds, id];
      return { selectedIds };
    });
  },

  selectAll: () => {
    const { reviewItems, activeFilter } = get();
    const filtered = activeFilter === 'all'
      ? reviewItems
      : reviewItems.filter((item) => item.reviewStatus === activeFilter);
    set({ selectedIds: filtered.map((item) => item.id) });
  },

  clearSelection: () => set({ selectedIds: [] }),

  confirmItem: async (type: 'insight' | 'strategy', id: string) => {
    const operator = '老薛';
    const logEntry = {
      action: 'confirmed' as const,
      timestamp: new Date().toISOString(),
      operator,
    };

    if (type === 'insight') {
      await updateInsightReview(id, 'confirmed', [logEntry]);
    } else {
      await updateStrategyCardReview(id, 'confirmed', [logEntry]);
    }

    set((state) => ({
      reviewItems: state.reviewItems.map((item) =>
        item.id === id ? { ...item, reviewStatus: 'confirmed' as const } : item,
      ),
    }));
  },

  rejectItem: async (type: 'insight' | 'strategy', id: string, reason: string) => {
    const operator = '老薛';
    const logEntry = {
      action: 'rejected' as const,
      timestamp: new Date().toISOString(),
      operator,
      changes: reason,
    };

    if (type === 'insight') {
      await updateInsightReview(id, 'rejected', [logEntry]);
    } else {
      await updateStrategyCardReview(id, 'rejected', [logEntry]);
    }

    set((state) => ({
      reviewItems: state.reviewItems.map((item) =>
        item.id === id ? { ...item, reviewStatus: 'rejected' as const } : item,
      ),
    }));
  },

  batchConfirm: async () => {
    const { selectedIds } = get();
    for (const id of selectedIds) {
      const item = get().reviewItems.find((i) => i.id === id);
      if (item) {
        await get().confirmItem(item.itemType, id);
      }
    }
    set({ selectedIds: [] });
  },

  batchReject: async (reason: string) => {
    const { selectedIds } = get();
    for (const id of selectedIds) {
      const item = get().reviewItems.find((i) => i.id === id);
      if (item) {
        await get().rejectItem(item.itemType, id, reason);
      }
    }
    set({ selectedIds: [] });
  },

  getPendingItems: () => {
    return get().reviewItems.filter((item) => item.reviewStatus === 'pending');
  },
}));
