import { create } from 'zustand';
import type { Brand } from '../types/brand';
import {
  getAllBrands,
  putBrand,
  updateBrand as dbUpdateBrand,
  deleteBrand as dbDeleteBrand,
} from '../db/brand.db';

interface BrandState {
  brands: Brand[];
  currentBrandId: string | null;
  isLoading: boolean;

  loadBrands: () => Promise<void>;
  switchBrand: (id: string) => void;
  addBrand: (brand: Brand) => Promise<void>;
  updateBrand: (id: string, updates: Partial<Brand>) => Promise<void>;
  deleteBrand: (id: string) => Promise<void>;
  getCurrentBrand: () => Brand | undefined;
}

export const useBrandStore = create<BrandState>((set, get) => ({
  brands: [],
  currentBrandId: null,
  isLoading: false,

  loadBrands: async () => {
    set({ isLoading: true });
    try {
      const brands = await getAllBrands();
      const saved = localStorage.getItem('vos2-current-brand');
      const currentBrandId = saved || brands[0]?.id || null;
      set({ brands, currentBrandId, isLoading: false });
    } catch (err) {
      console.error('Failed to load brands:', err);
      set({ isLoading: false });
    }
  },

  switchBrand: (id: string) => {
    set({ currentBrandId: id });
    localStorage.setItem('vos2-current-brand', id);
  },

  addBrand: async (brand: Brand) => {
    await putBrand(brand);
    await get().loadBrands();
  },

  updateBrand: async (id: string, updates: Partial<Brand>) => {
    await dbUpdateBrand(id, updates);
    await get().loadBrands();
  },

  deleteBrand: async (id: string) => {
    await dbDeleteBrand(id);
    await get().loadBrands();
    const { brands, currentBrandId } = get();
    if (currentBrandId === id) {
      const nextId = brands[0]?.id || null;
      set({ currentBrandId: nextId });
    }
  },

  getCurrentBrand: () => {
    const { brands, currentBrandId } = get();
    return brands.find((b) => b.id === currentBrandId);
  },
}));
