/**
 * V1 → V2 data migration utility.
 *
 * Detects V1 data in localStorage (voc-comments, voc-brand-data, etc.)
 * and migrates it into the V2 Dexie.js database under brand_001.
 *
 * Enhanced: detailed logging, progress reporting, result callback.
 */

import { db } from '../db/db';
import type { Brand } from '../types/brand';
import type { Comment } from '../types/comment';
import { nanoid } from 'nanoid';

/** Migration result with detailed stats */
export interface MigrationResult {
  migrated: boolean;
  brands: number;
  comments: number;
  apiSettings: boolean;
  callLogs: boolean;
  details: string[];
}

/** Check if V1 data exists in localStorage AND migration hasn't been done */
export function hasV1Data(): boolean {
  if (localStorage.getItem('vos2-migrated') === 'true') {
    return false;
  }
  const keys = ['voc-comments', 'voc-brand-data', 'voc-api-settings', 'voc-call-logs'];
  return keys.some((key) => localStorage.getItem(key) !== null);
}

/** Migrate V1 data to V2 DexieDB */
export async function migrateV1ToV2(
  onProgress?: (msg: string) => void,
): Promise<MigrationResult> {
  const result: MigrationResult = {
    migrated: false,
    brands: 0,
    comments: 0,
    apiSettings: false,
    callLogs: false,
    details: [],
  };

  if (!hasV1Data()) {
    return result;
  }

  const log = (msg: string) => {
    console.log(`[Migration] ${msg}`);
    result.details.push(msg);
    onProgress?.(msg);
  };

  result.migrated = true;
  log('检测到 V1 数据，开始迁移...');

  try {
    // ── Step 1: Migrate brand data ──
    const v1BrandData = localStorage.getItem('voc-brand-data');
    if (v1BrandData) {
      log('→ 迁移品牌数据...');
      const v1Brand = JSON.parse(v1BrandData);

      const defaultBrand: Brand = {
        id: 'brand_001',
        name: v1Brand.name || '我的品牌',
        industry: v1Brand.industry || '',
        categoryId: null,
        logoUrl: v1Brand.logoUrl || '',
        createdAt: new Date().toISOString(),
        config: {
          products: (v1Brand.products || []).map((p: Record<string, unknown>) => ({
            name: String(p.name || ''),
            sku: String(p.sku || ''),
            price: Number(p.price) || 0,
            unit: String(p.unit || ''),
            coreIngredients: Array.isArray(p.coreIngredients) ? p.coreIngredients as string[] : [],
            targetUsers: Array.isArray(p.targetUsers) ? p.targetUsers as string[] : [],
            sellingPoints: Array.isArray(p.sellingPoints) ? p.sellingPoints as string[] : [],
            status: String(p.status || 'active'),
          })),
          brandStory: v1Brand.brandStory || '',
          visualStyle: v1Brand.visualStyle || '',
          tone: v1Brand.tone || '',
          keywords: {
            brandWords: v1Brand.keywords?.brandWords || [],
            categoryWords: v1Brand.keywords?.categoryWords || [],
            sceneWords: v1Brand.keywords?.sceneWords || [],
            audienceWords: v1Brand.keywords?.audienceWords || [],
          },
          contentGuidelines: {
            do: v1Brand.contentGuidelines?.do || [],
            dont: v1Brand.contentGuidelines?.dont || [],
          },
        },
        competitors: (v1Brand.competitors || []).map((c: Record<string, unknown>) => ({
          id: String(c.id || nanoid()),
          name: String(c.name || ''),
          positioning: String(c.positioning || ''),
          strengths: Array.isArray(c.strengths) ? c.strengths as string[] : [],
          weaknesses: Array.isArray(c.weaknesses) ? c.weaknesses as string[] : [],
          keyProducts: Array.isArray(c.keyProducts) ? c.keyProducts as { name: string; price: number; comparison: string }[] : [],
          contentStyle: String(c.contentStyle || ''),
          commentHighlights: {
            praise: Array.isArray(c.commentHighlights?.praise) ? c.commentHighlights.praise as string[] : [],
            complaint: Array.isArray(c.commentHighlights?.complaint) ? c.commentHighlights.complaint as string[] : [],
          },
          swot: {
            S: String(c.swot?.S || ''),
            W: String(c.swot?.W || ''),
            O: String(c.swot?.O || ''),
            T: String(c.swot?.T || ''),
          },
        })),
        stats: {
          totalComments: 0,
          confirmedInsights: 0,
          strategyCards: { total: 0, active: 0, draft: 0, archived: 0 },
          lastImportAt: null,
        },
      };

      // Check if brand_001 already exists
      const existingBrand = await db.brands.get('brand_001');
      if (!existingBrand) {
        await db.brands.put(defaultBrand);
        result.brands = 1;
        log(`  ✓ 品牌「${defaultBrand.name}」迁移完成`);
      } else {
        log('  ⓘ 品牌 brand_001 已存在，跳过');
      }
    } else {
      log('  ⓘ 无 V1 品牌数据');
    }

    // ── Step 2: Migrate comments ──
    const v1Comments = localStorage.getItem('voc-comments');
    if (v1Comments) {
      log('→ 迁移评论数据...');
      const v1AllComments = JSON.parse(v1Comments);

      if (!Array.isArray(v1AllComments) || v1AllComments.length === 0) {
        log('  ⓘ V1 评论数据为空');
      } else {
        const comments: Comment[] = v1AllComments.map(
          (c: Record<string, unknown>, idx: number) => ({
            id: idx + 1,
            brandId: 'brand_001',
            sourceHash: '',
            content: String(c.content || ''),
            platform: String(c.platform || '抖音'),
            category: String(c.category || 'content'),
            type: String(c.type || 'demand'),
            sentiment: String(c.sentiment || 'neutral'),
            labels: Array.isArray(c.labels) ? c.labels as string[] : [],
            author: String(c.author || c.userName || ''),
            userName: String(c.userName || c.author || ''),
            douyinId: String(c.douyinId || ''),
            date: String(c.date || ''),
            likes: Number(c.likes) || 0,
            commentTime: String(c.commentTime || ''),
            ipAddress: String(c.ipAddress || ''),
            subCommentCount: Number(c.subCommentCount) || 0,
            videoId: String(c.videoId || ''),
            videoLink: String(c.videoLink || ''),
            userUid: String(c.userUid || ''),
            userLink: String(c.userLink || ''),
            parentCommentId: String(c.parentCommentId || ''),
            parentCommentContent: String(c.parentCommentContent || ''),
            parentUserUid: String(c.parentUserUid || ''),
            parentUserName: String(c.parentUserName || ''),
            refCommentId: String(c.refCommentId || ''),
            refCommentContent: String(c.refCommentContent || ''),
            refUserUid: String(c.refUserUid || ''),
            refUserName: String(c.refUserName || ''),
            isCompetitor: Boolean(c.isCompetitor),
            competitorId: (c.competitorId as number) || null,
            isAnalyzed: Boolean(c.isAnalyzed),
            importedAt: String(c.importedAt || new Date().toISOString()),
            importBatchId: String(c.importBatchId || 'migrate_v1'),
          }),
        );

        await db.comments.bulkPut(comments);
        result.comments = comments.length;
        log(`  ✓ ${comments.length} 条评论迁移完成`);

        // Update brand stats
        const brand = await db.brands.get('brand_001');
        if (brand) {
          const strategyCards = await db.strategyCards
            .where({ brandId: 'brand_001' })
            .toArray();
          await db.brands.update('brand_001', {
            stats: {
              totalComments: comments.length,
              confirmedInsights: brand.stats?.confirmedInsights ?? 0,
              strategyCards: {
                total: strategyCards.length,
                active: strategyCards.filter((c) => c.status === 'active').length,
                draft: strategyCards.filter((c) => c.status === 'draft').length,
                archived: strategyCards.filter((c) => c.status === 'archived').length,
              },
              lastImportAt: new Date().toISOString(),
            },
          });
        }
      }
    } else {
      log('  ⓘ 无 V1 评论数据');
    }

    // ── Step 3: Migrate API settings ──
    const v1ApiSettings = localStorage.getItem('voc-api-settings');
    if (v1ApiSettings) {
      localStorage.setItem('vos-api-settings', v1ApiSettings);
      result.apiSettings = true;
      log('→ ✓ API 配置迁移完成');
    } else {
      log('  ⓘ 无 V1 API 配置');
    }

    // ── Step 4: Migrate call logs ──
    const v1CallLogs = localStorage.getItem('voc-call-logs');
    if (v1CallLogs) {
      localStorage.setItem('vos-call-logs', v1CallLogs);
      result.callLogs = true;
      log('→ ✓ 调用日志迁移完成');
    } else {
      log('  ⓘ 无 V1 调用日志');
    }

    // ── Finalize ──
    localStorage.setItem('vos2-migrated', 'true');
    log(`✅ 迁移完成: ${result.brands} 品牌, ${result.comments} 评论`);
  } catch (err) {
    log(`❌ 迁移失败: ${err instanceof Error ? err.message : String(err)}`);
    console.error('[Migration] Error:', err);
  }

  return result;
}
